package main

import (
	"fmt"
	"os"
	"strconv"
	"strings"

	"github.com/anikchand461/task/internal/task"
)

func printHelp() {
	fmt.Print(`
Task CLI 📝

Usage:
  task <command> [arguments]

Commands:
  add "task name"     Add a new task
  list                List all tasks
  done <id>            Mark a task as done
  done all             Mark all tasks as done
  edit <id> "new name" Edit a task description
  clear                Delete all tasks
  help                 Show this help message
  delete <id>          Remove a specific task


Examples:
  task add "Buy milk"
  task list
  task done 1
  task done all
  task edit 1 "Buy groceries and milk"
  task clear
`)
}

func main() {
	if len(os.Args) < 2 ||
		os.Args[1] == "help" ||
		os.Args[1] == "-h" ||
		os.Args[1] == "--help" {

		printHelp()
		return
	}

	unlock, err := task.AcquireLock()
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	defer unlock()

	switch os.Args[1] {

	case "add":
		if len(os.Args) < 3 {
			fmt.Println("Usage: task add \"task 1\" \"task 2\" ...")
			return
		}

		tasks := os.Args[2:]

		err := task.Add(tasks...)
		if err != nil {
			fmt.Println("Error:", err)
			return
		}

		fmt.Printf("✅ Added %d task(s)\n", len(tasks))
	case "list":
		err := task.List()
		if err != nil {
			fmt.Println("Error:", err)
		}

	case "clear":
		err := task.Clear()
		if err != nil {
			fmt.Println("Error:", err)
			return
		}
		fmt.Println("All tasks deleted")

	case "edit":
		if len(os.Args) < 4 {
			fmt.Println("Usage: task edit <number> \"<new description>\"")
			fmt.Println("Example: task edit 1 \"Buy groceries\"")
			return
		}

		taskNum, err := strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Println("❌ Error: Invalid task number")
			fmt.Println("Example: task edit 1 \"Updated description\"")
			return
		}

		newDescription := os.Args[3]

		if strings.TrimSpace(newDescription) == "" {
			fmt.Println("❌ Error: Task description cannot be empty")
			return
		}

		if err := task.EditTask(taskNum, newDescription); err != nil {
			fmt.Printf("❌ Error: %v\n", err)
			return
		}

		fmt.Printf("✅ Task #%d updated successfully\n", taskNum)

	case "done":
		if len(os.Args) < 3 {
			fmt.Println("Usage: task done <id | all> [<id> ...]")
			return
		}

		if os.Args[2] == "all" {
			err := task.DoneAll()
			if err != nil {
				fmt.Println("Error:", err)
				return
			}
			fmt.Println("All tasks marked as done")
			return
		}

		// Join all IDs with commas to support: task done 1 3 or task done "1,3"
		idStr := strings.Join(os.Args[2:], ",")
		err := task.Done(idStr)
		if err != nil {
			fmt.Println("Error:", err)
			return
		}
		fmt.Println("Tasks marked as done")

	case "delete":
		if len(os.Args) < 3 {
			fmt.Println("Usage: task delete <id>")
			return
		}

		taskNum, err := strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Println("❌ Error: Invalid task number")
			return
		}

		if err := task.DeleteTask(taskNum); err != nil {
			fmt.Printf("❌ Error: %v\n", err)
			return
		}

		fmt.Printf("✅ Task #%d deleted successfully\n", taskNum)

	default:
		fmt.Println("Unknown command:", os.Args[1])
		printHelp()
	}
}

package task

import "os"

func Add(tasks ...string) error {
	path, err := dataFilePath()
	if err != nil {
		return err
	}

	f, err := os.OpenFile(path,
		os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if err != nil {
		return err
	}
	defer f.Close()

	for _, task := range tasks {
		if task == "" {
			continue
		}
		_, err := f.WriteString(task + "|pending\n")
		if err != nil {
			return err
		}
	}

	return nil
}

package task

import (
	"os"
)

func Clear() error {
	path, err := dataFilePath()
	if err != nil {
		return err
	}

	// Delete the file
	return os.Remove(path)
}

package task

import (
	"bufio"
	"fmt"
	"os"
	"strings"
)


func DeleteTask(taskNumber int) error {
	path, err := dataFilePath()
	if err != nil {
		return err
	}

	f, err := os.Open(path)
	if err != nil {
		return err
	}
	defer f.Close()

	var lines []string
	scanner := bufio.NewScanner(f)
	for scanner.Scan() {
		lines = append(lines, scanner.Text())
	}
	if err := scanner.Err(); err != nil {
		return err
	}

	if taskNumber < 1 || taskNumber > len(lines) {
		return fmt.Errorf("invalid task number: %d (valid range: 1-%d)", taskNumber, len(lines))
	}

	lines = append(lines[:taskNumber-1], lines[taskNumber:]...)

	return os.WriteFile(
		path,
		[]byte(strings.Join(lines, "\n")+"\n"),
		0644,
	)
}

package task

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

func Done(idStr string) error {
	path, err := dataFilePath()
	if err != nil {
		return err
	}

	// Parse comma-separated IDs
	idParts := strings.Split(idStr, ",")
	idsToMark := make(map[int]bool)

	for _, part := range idParts {
		trimmed := strings.TrimSpace(part)
		id, err := strconv.Atoi(trimmed)
		if err != nil {
			return fmt.Errorf("invalid task id: %s", trimmed)
		}
		idsToMark[id] = true
	}

	// Read all tasks
	f, err := os.Open(path)
	if err != nil {
		return err
	}
	defer f.Close()

	scanner := bufio.NewScanner(f)
	var tasks []string
	i := 1
	for scanner.Scan() {
		line := scanner.Text()
		if idsToMark[i] {
			// Mark this task as done
			parts := strings.Split(line, "|")
			if len(parts) >= 2 {
				parts[1] = "done"
				line = strings.Join(parts, "|")
			}
		}
		tasks = append(tasks, line)
		i++
	}

	if err := scanner.Err(); err != nil {
		return err
	}

	// Write back all tasks
	f, err = os.Create(path)
	if err != nil {
		return err
	}
	defer f.Close()

	for _, task := range tasks {
		_, err = f.WriteString(task + "\n")
		if err != nil {
			return err
		}
	}

	return nil
}

func DoneAll() error {
	// Get absolute path to ~/.task/tasks.txt
	path, err := dataFilePath()
	if err != nil {
		return err
	}

	// Open file
	f, err := os.Open(path)
	if err != nil {
		return err
	}
	defer f.Close()

	// Read all lines
	var lines []string
	scanner := bufio.NewScanner(f)
	for scanner.Scan() {
		lines = append(lines, scanner.Text())
	}
	if err := scanner.Err(); err != nil {
		return err
	}

	// Mark all tasks as done
	for i, line := range lines {
		parts := strings.Split(line, "|")
		if len(parts) >= 2 {
			parts[1] = "done"
			lines[i] = strings.Join(parts, "|")
		}
	}

	// Write back to file
	return os.WriteFile(
		path,
		[]byte(strings.Join(lines, "\n")+"\n"),
		0644,
	)
}

package task

import (
	"bufio"
	"fmt"
	"os"
	"strings"
)

// EditTask updates the description of an existing task
func EditTask(taskNumber int, newDescription string) error {
	// Get absolute path to ~/.task/tasks.txt
	path, err := dataFilePath()
	if err != nil {
		return err
	}

	// Open file
	f, err := os.Open(path)
	if err != nil {
		return err
	}
	defer f.Close()

	// Read all lines
	var lines []string
	scanner := bufio.NewScanner(f)
	for scanner.Scan() {
		lines = append(lines, scanner.Text())
	}
	if err := scanner.Err(); err != nil {
		return err
	}

	// Validate task number
	if taskNumber < 1 || taskNumber > len(lines) {
		return fmt.Errorf("invalid task number: %d (valid range: 1-%d)", taskNumber, len(lines))
	}

	// Update task description (preserve status)
	parts := strings.Split(lines[taskNumber-1], "|")
	if len(parts) >= 2 {
		// Keep the status (pending/done), update description
		parts[0] = newDescription
		lines[taskNumber-1] = strings.Join(parts, "|")
	}

	// Write back to file
	return os.WriteFile(
		path,
		[]byte(strings.Join(lines, "\n")+"\n"),
		0644,
	)
}

package task

import (
	"bufio"
	"fmt"
	"os"
	"strings"
)

func List() error {
	path, err := dataFilePath()
	if err != nil {
		return err
	}

	// If file doesn't exist → empty list
	if _, err := os.Stat(path); os.IsNotExist(err) {
		fmt.Println("No tasks found.")
		return nil
	}

	f, err := os.Open(path)
	if err != nil {
		return err
	}
	defer f.Close()

	scanner := bufio.NewScanner(f)
	i := 1
	for scanner.Scan() {
		parts := strings.Split(scanner.Text(), "|")
		if len(parts) < 2 {
			continue
		}

		status := "⭕️"
		if parts[1] == "done" {
			status = "✅"
		}

		fmt.Printf("%d. %s %s\n", i, status, parts[0])
		i++
	}

	return scanner.Err()
}

package task

import (
	"fmt"
	"os"
	"path/filepath"
	"time"
)


func AcquireLock() (func(), error) {
	path, err := dataFilePath()
	if err != nil {
		return nil, err
	}

	// Lock file acts as a flag: if it exists, the DB is busy.
	lockPath := filepath.Join(filepath.Dir(path), "tasks.lock")

	for i := 0; i < 10; i++ { // Try 10 times (1 second total)

		f, err := os.OpenFile(lockPath, os.O_CREATE|os.O_EXCL, 0644)
		if err == nil {

			f.Close()

			return func() {
				os.Remove(lockPath)
			}, nil
		}


		if !os.IsExist(err) {
			return nil, err
		}


		time.Sleep(100 * time.Millisecond)
	}

	return nil, fmt.Errorf("could not acquire lock: another task process is running")
}

package task

import (
	"os"
	"path/filepath"
)

func dataFilePath() (string, error) {
	home, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}

	dir := filepath.Join(home, ".task")
	err = os.MkdirAll(dir, 0755)
	if err != nil {
		return "", err
	}

	return filepath.Join(dir, "tasks.txt"), nil
}
